class Solution:
    def longestDecomposition(self, text: str) -> int:
        n = len(text)
        l, r = 0, n - 1
        res = 0
        while l <= r:
            length = 1
            while l + length - 1 < r - length + 1:
                if text[l:l+length] == text[r-length+1:r+1]:
                    res += 2
                    l += length
                    r -= length
                    break
                length += 1
            else:
                res += 1
                break
        return res

